async function upsert(table, rows) {
  const r = await fetch(`${BASE}/rest/v1/${table}`, { method: "POST", headers: H, body: JSON.stringify(rows) });
  if (!r.ok) console.error(`${table} error:`, (await r.text()).slice(0, 300));
  else console.log(`\u2713 ${table}: ${rows.length} rows`);
}

// Generate a UUID v4
function uuid() {
  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === "x" ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

// Delete all questions for given quiz IDs, then insert fresh in batches
async function insertQuestions(quizIds, rows) {
  // Assign client-side UUIDs
  const withIds = rows.map(r => ({ id: uuid(), ...r }));
  // Delete existing questions for these quizzes
  const inParam = `(${quizIds.map(id => `"${id}"`).join(",")})`;
  const delR = await fetch(`${BASE}/rest/v1/quiz_questions?quiz_id=in.${inParam}`, { method: "DELETE", headers: H2 });
  if (!delR.ok) { console.error("quiz_questions delete error:", (await delR.text()).slice(0, 200)); }
  else { console.log(`\u2713 quiz_questions: deleted old rows`); }
  // Insert in batches of 30 to avoid request size limits
  const BATCH = 30;
  for (let i = 0; i < withIds.length; i += BATCH) {
    const batch = withIds.slice(i, i + BATCH);
    const r = await fetch(`${BASE}/rest/v1/quiz_questions`, { method: "POST", headers: H2, body: JSON.stringify(batch) });
    if (!r.ok) { console.error(`quiz_questions batch ${Math.floor(i/BATCH)+1} error:`, (await r.text()).slice(0, 300)); return; }
  }
  console.log(`\u2713 quiz_questions: ${withIds.length} rows inserted`);
}

